function withOptionalEnv(
  name: string,
  value: string | undefined,
  fn: () => Promise<void>,
): Promise<void> {
  const previous = process.env[name];
  if (value === undefined) {
    process.env[name] = undefined;
  } else {
    process.env[name] = value;
  }

  return fn().finally(() => {
    if (previous === undefined) {
      process.env[name] = undefined;
    } else {
      process.env[name] = previous;
    }
  });
}

